"""
Race comparison data loading and synchronization module.
"""

from dataclasses import dataclass, field
from enum import Enum, auto
from typing import Optional, Dict, List, Any, Tuple
import numpy as np


class SyncMode(Enum):
    LAP_BASED = auto()
    TIME_BASED = auto()
    DISTANCE_BASED = auto()


class ViewMode(Enum):
    SPLIT = auto()
    OVERLAY = auto()
    DIFFERENCE = auto()


@dataclass
class RaceInfo:
    year: int
    round_number: int
    session_type: str = 'R'
    event_name: str = ''
    circuit_name: str = ''
    country: str = ''
    date: str = ''
    total_laps: int = 0

    def __post_init__(self):
        if self.year is None or self.year < 1950 or self.year > 2100:
            raise ValueError(f"Invalid year: {self.year}")
        if self.round_number is None or self.round_number < 1:
            raise ValueError(f"Invalid round number: {self.round_number}")
        if self.session_type not in ('R', 'S', 'Q', 'SQ'):
            raise ValueError(f"Invalid session type: {self.session_type}")


@dataclass
class RaceComparisonData:
    race_a: Dict[str, Any] = field(default_factory=dict)
    race_b: Dict[str, Any] = field(default_factory=dict)
    info_a: Optional[RaceInfo] = None
    info_b: Optional[RaceInfo] = None
    track_a: Optional[Dict[str, Any]] = None
    track_b: Optional[Dict[str, Any]] = None
    example_lap_a: Optional[Any] = None
    example_lap_b: Optional[Any] = None
    lap_sync_map: Dict[int, Tuple[int, int]] = field(default_factory=dict)
    time_sync_map: List[Tuple[float, int, int]] = field(default_factory=list)
    distance_sync_map: List[Tuple[float, int, int]] = field(default_factory=list)

    @property
    def is_loaded(self) -> bool:
        return bool(self.race_a and self.race_b)

    @property
    def frames_a(self) -> List[Dict]:
        return self.race_a.get('frames', []) if self.race_a else []

    @property
    def frames_b(self) -> List[Dict]:
        return self.race_b.get('frames', []) if self.race_b else []

    @property
    def driver_colors_a(self) -> Dict[str, Tuple[int, int, int]]:
        return self.race_a.get('driver_colors', {}) if self.race_a else {}

    @property
    def driver_colors_b(self) -> Dict[str, Tuple[int, int, int]]:
        return self.race_b.get('driver_colors', {}) if self.race_b else {}

    @property
    def track_statuses_a(self) -> List[Dict]:
        return self.race_a.get('track_statuses', []) if self.race_a else []

    @property
    def track_statuses_b(self) -> List[Dict]:
        return self.race_b.get('track_statuses', []) if self.race_b else []

    def get_total_laps(self, race: str = 'a') -> int:
        data = self.race_a if race.lower() == 'a' else self.race_b
        return data.get('total_laps', 0) if data else 0


class ComparisonDataLoader:
    def __init__(self):
        self._comparison_data: Optional[RaceComparisonData] = None
        self._load_errors: List[str] = []

    @property
    def comparison_data(self) -> Optional[RaceComparisonData]:
        return self._comparison_data

    @property
    def load_errors(self) -> List[str]:
        return list(self._load_errors)

    def load_races(self, year_a: int, round_a: int, year_b: int, round_b: int,
                   session_type_a: str = 'R', session_type_b: str = 'R') -> Optional[RaceComparisonData]:
        self._load_errors.clear()
        self._comparison_data = None

        try:
            info_a = RaceInfo(year=year_a, round_number=round_a, session_type=session_type_a)
            info_b = RaceInfo(year=year_b, round_number=round_b, session_type=session_type_b)
        except ValueError as e:
            self._load_errors.append(f"Invalid race parameters: {e}")
            return None

        race_a_data, session_a, example_lap_a = self._load_single_race(info_a, "Race A")
        if race_a_data is None:
            return None

        if session_a is not None:
            try:
                info_a.event_name = session_a.event.get('EventName', '')
                info_a.circuit_name = session_a.event.get('Location', '')
                info_a.country = session_a.event.get('Country', '')
                event_date = session_a.event.get('EventDate')
                if event_date:
                    info_a.date = event_date.strftime('%Y-%m-%d')
                info_a.total_laps = race_a_data.get('total_laps', 0)
            except Exception as e:
                self._load_errors.append(f"Warning: Could not extract race A info: {e}")

        race_b_data, session_b, example_lap_b = self._load_single_race(info_b, "Race B")
        if race_b_data is None:
            return None

        if session_b is not None:
            try:
                info_b.event_name = session_b.event.get('EventName', '')
                info_b.circuit_name = session_b.event.get('Location', '')
                info_b.country = session_b.event.get('Country', '')
                event_date = session_b.event.get('EventDate')
                if event_date:
                    info_b.date = event_date.strftime('%Y-%m-%d')
                info_b.total_laps = race_b_data.get('total_laps', 0)
            except Exception as e:
                self._load_errors.append(f"Warning: Could not extract race B info: {e}")

        track_a = self._build_track_geometry(example_lap_a, "Race A")
        track_b = self._build_track_geometry(example_lap_b, "Race B")

        comparison_data = RaceComparisonData(
            race_a=race_a_data, race_b=race_b_data,
            info_a=info_a, info_b=info_b,
            track_a=track_a, track_b=track_b,
            example_lap_a=example_lap_a, example_lap_b=example_lap_b,
        )

        self._build_sync_mappings(comparison_data)
        self._comparison_data = comparison_data
        return comparison_data

    def _load_single_race(self, info: RaceInfo, race_label: str) -> Tuple[Optional[Dict], Optional[Any], Optional[Any]]:
        try:
            from src.f1_data import load_session, get_race_telemetry, enable_cache, get_circuit_rotation
            enable_cache()

            print(f"Loading {race_label}: {info.year} Round {info.round_number}...")
            session = load_session(info.year, info.round_number, info.session_type)

            if session is None:
                self._load_errors.append(f"Failed to load session for {race_label}")
                return None, None, None

            telemetry = get_race_telemetry(session, session_type=info.session_type)
            if telemetry is None or not telemetry.get('frames'):
                self._load_errors.append(f"No telemetry data for {race_label}")
                return None, None, None

            try:
                telemetry['circuit_rotation'] = get_circuit_rotation(session)
            except Exception as e:
                self._load_errors.append(f"Warning: Could not get circuit rotation for {race_label}: {e}")
                telemetry['circuit_rotation'] = 0.0

            example_lap = self._get_example_lap(session, info)
            return telemetry, session, example_lap
        except Exception as e:
            self._load_errors.append(f"Error loading {race_label}: {e}")
            return None, None, None

    def _get_example_lap(self, session, info: RaceInfo) -> Optional[Any]:
        example_lap = None
        try:
            from src.f1_data import load_session
            quali_session = load_session(info.year, info.round_number, 'Q')
            if quali_session is not None and len(quali_session.laps) > 0:
                fastest_quali = quali_session.laps.pick_fastest()
                if fastest_quali is not None:
                    quali_telemetry = fastest_quali.get_telemetry()
                    if 'DRS' in quali_telemetry.columns:
                        example_lap = quali_telemetry
        except Exception:
            pass

        if example_lap is None:
            try:
                fastest_lap = session.laps.pick_fastest()
                if fastest_lap is not None:
                    example_lap = fastest_lap.get_telemetry()
            except Exception:
                pass
        return example_lap

    def _build_track_geometry(self, example_lap, race_label: str) -> Optional[Dict[str, Any]]:
        if example_lap is None:
            self._load_errors.append(f"No example lap for {race_label} track geometry")
            return None
        try:
            from src.ui_components import build_track_from_example_lap
            result = build_track_from_example_lap(example_lap)
            if result is None or len(result) < 10:
                self._load_errors.append(f"Invalid track geometry for {race_label}")
                return None
            (plot_x_ref, plot_y_ref, x_inner, y_inner, x_outer, y_outer,
             x_min, x_max, y_min, y_max, drs_zones) = result
            return {
                'plot_x_ref': plot_x_ref, 'plot_y_ref': plot_y_ref,
                'x_inner': x_inner, 'y_inner': y_inner,
                'x_outer': x_outer, 'y_outer': y_outer,
                'x_min': x_min, 'x_max': x_max, 'y_min': y_min, 'y_max': y_max,
                'drs_zones': drs_zones,
            }
        except Exception as e:
            self._load_errors.append(f"Error building track geometry for {race_label}: {e}")
            return None

    def _build_sync_mappings(self, data: RaceComparisonData) -> None:
        frames_a, frames_b = data.frames_a, data.frames_b
        if not frames_a or not frames_b:
            return
        data.lap_sync_map = self._build_lap_sync_map(frames_a, frames_b)
        data.time_sync_map = self._build_time_sync_map(frames_a, frames_b)
        data.distance_sync_map = self._build_distance_sync_map(frames_a, frames_b)

    def _build_lap_sync_map(self, frames_a: List[Dict], frames_b: List[Dict]) -> Dict[int, Tuple[int, int]]:
        lap_map = {}
        lap_starts_a, prev_lap = {}, 0
        for i, frame in enumerate(frames_a):
            lap = frame.get('lap', 1)
            if lap != prev_lap and lap not in lap_starts_a:
                lap_starts_a[lap] = i
            prev_lap = lap

        lap_starts_b, prev_lap = {}, 0
        for i, frame in enumerate(frames_b):
            lap = frame.get('lap', 1)
            if lap != prev_lap and lap not in lap_starts_b:
                lap_starts_b[lap] = i
            prev_lap = lap

        for lap in sorted(set(lap_starts_a.keys()) | set(lap_starts_b.keys())):
            lap_map[lap] = (lap_starts_a.get(lap, 0), lap_starts_b.get(lap, 0))
        return lap_map

    def _build_time_sync_map(self, frames_a: List[Dict], frames_b: List[Dict]) -> List[Tuple[float, int, int]]:
        time_map = []
        times_a = [f.get('t', 0.0) for f in frames_a]
        times_b = [f.get('t', 0.0) for f in frames_b]
        if not times_a or not times_b:
            return time_map

        max_time = max(max(times_a), max(times_b))
        current_time, idx_a, idx_b = 0.0, 0, 0
        while current_time <= max_time:
            while idx_a < len(times_a) - 1 and times_a[idx_a + 1] <= current_time:
                idx_a += 1
            while idx_b < len(times_b) - 1 and times_b[idx_b + 1] <= current_time:
                idx_b += 1
            time_map.append((current_time, idx_a, idx_b))
            current_time += 1.0
        return time_map

    def _build_distance_sync_map(self, frames_a: List[Dict], frames_b: List[Dict]) -> List[Tuple[float, int, int]]:
        distance_map = []
        for pct in range(0, 101):
            pct_float = pct / 100.0
            frame_a = self._find_frame_by_rel_dist(frames_a, pct_float)
            frame_b = self._find_frame_by_rel_dist(frames_b, pct_float)
            distance_map.append((pct_float, frame_a, frame_b))
        return distance_map

    def _find_frame_by_rel_dist(self, frames: List[Dict], target_pct: float) -> int:
        if not frames:
            return 0
        best_idx, best_diff = 0, float('inf')
        for i, frame in enumerate(frames):
            drivers = frame.get('drivers', {})
            if not drivers:
                continue
            leader_dist = max((d.get('rel_dist', 0.0) for d in drivers.values()), default=0.0)
            diff = abs(leader_dist - target_pct)
            if diff < best_diff:
                best_diff, best_idx = diff, i
        return best_idx


class SyncController:
    def __init__(self, comparison_data: RaceComparisonData):
        self._data = comparison_data
        self._sync_mode = SyncMode.LAP_BASED
        self._primary_frame_idx = 0.0
        self._secondary_frame_idx = 0.0

    @property
    def sync_mode(self) -> SyncMode:
        return self._sync_mode

    @sync_mode.setter
    def sync_mode(self, mode: SyncMode) -> None:
        if not isinstance(mode, SyncMode):
            raise ValueError(f"Invalid sync mode: {mode}")
        self._sync_mode = mode
        self._update_secondary_frame()

    @property
    def frame_index_a(self) -> int:
        return max(0, min(int(self._primary_frame_idx), len(self._data.frames_a) - 1))

    @property
    def frame_index_b(self) -> int:
        return max(0, min(int(self._secondary_frame_idx), len(self._data.frames_b) - 1))

    @property
    def frame_index_a_float(self) -> float:
        return self._primary_frame_idx

    @frame_index_a_float.setter
    def frame_index_a_float(self, value: float) -> None:
        max_frame = max(0, len(self._data.frames_a) - 1)
        self._primary_frame_idx = max(0.0, min(float(value), float(max_frame)))
        self._update_secondary_frame()

    def advance(self, delta_frames: float) -> None:
        max_frame = max(0, len(self._data.frames_a) - 1)
        self._primary_frame_idx = max(0.0, min(self._primary_frame_idx + delta_frames, float(max_frame)))
        self._update_secondary_frame()

    def seek(self, frame_idx: float) -> None:
        self.frame_index_a_float = frame_idx

    def _update_secondary_frame(self) -> None:
        if not self._data.frames_a or not self._data.frames_b:
            return
        if self._sync_mode == SyncMode.LAP_BASED:
            self._sync_by_lap()
        elif self._sync_mode == SyncMode.TIME_BASED:
            self._sync_by_time()
        elif self._sync_mode == SyncMode.DISTANCE_BASED:
            self._sync_by_distance()

    def _sync_by_lap(self) -> None:
        frame_a = self.frame_index_a
        if frame_a >= len(self._data.frames_a):
            return
        current_lap = self._data.frames_a[frame_a].get('lap', 1)
        lap_map = self._data.lap_sync_map
        if current_lap in lap_map:
            lap_start_a, lap_start_b = lap_map[current_lap]
            self._secondary_frame_idx = float(lap_start_b + (frame_a - lap_start_a))
        else:
            self._sync_by_time()

    def _sync_by_time(self) -> None:
        frame_a = self.frame_index_a
        if frame_a >= len(self._data.frames_a):
            return
        current_time = self._data.frames_a[frame_a].get('t', 0.0)
        best_idx, best_diff = 0, float('inf')
        for i, frame in enumerate(self._data.frames_b):
            diff = abs(frame.get('t', 0.0) - current_time)
            if diff < best_diff:
                best_diff, best_idx = diff, i
            elif diff > best_diff:
                break
        self._secondary_frame_idx = float(best_idx)

    def _sync_by_distance(self) -> None:
        frame_a = self.frame_index_a
        if frame_a >= len(self._data.frames_a):
            return
        drivers_a = self._data.frames_a[frame_a].get('drivers', {})
        leader_dist_a = max((d.get('rel_dist', 0.0) for d in drivers_a.values()), default=0.0)
        best_idx, best_diff = 0, float('inf')
        for i, frame in enumerate(self._data.frames_b):
            drivers_b = frame.get('drivers', {})
            leader_dist_b = max((d.get('rel_dist', 0.0) for d in drivers_b.values()), default=0.0)
            diff = abs(leader_dist_b - leader_dist_a)
            if diff < best_diff:
                best_diff, best_idx = diff, i
        self._secondary_frame_idx = float(best_idx)


def compute_position_deltas(frame_a: Dict[str, Any], frame_b: Dict[str, Any],
                            driver_colors_a: Dict[str, Tuple[int, int, int]],
                            driver_colors_b: Dict[str, Tuple[int, int, int]]) -> Dict[str, Dict[str, Any]]:
    deltas = {}
    drivers_a, drivers_b = frame_a.get('drivers', {}), frame_b.get('drivers', {})
    positions_a = {code: data.get('position', 0) for code, data in drivers_a.items()}
    positions_b = {code: data.get('position', 0) for code, data in drivers_b.items()}

    for code in set(positions_a.keys()) | set(positions_b.keys()):
        pos_a, pos_b = positions_a.get(code), positions_b.get(code)
        if pos_a is not None and pos_b is not None:
            delta = pos_b - pos_a
            if delta < 0:
                color = (0, min(255, 100 + abs(delta) * 30), 0)
            elif delta > 0:
                color = (min(255, 100 + delta * 30), 0, 0)
            else:
                color = (128, 128, 128)
        else:
            delta, color = None, (100, 100, 100)
        deltas[code] = {
            'position_a': pos_a, 'position_b': pos_b, 'delta': delta, 'color': color,
            'color_a': driver_colors_a.get(code, (128, 128, 128)),
            'color_b': driver_colors_b.get(code, (128, 128, 128)),
        }
    return deltas
